6229 APInt ScalarEvolution::getConstantMultipleImpl(const SCEV *S) {
6230   uint64_t BitWidth = getTypeSizeInBits(S->getType());
6231   auto GetShiftedByZeros = [BitWidth](uint32_t TrailingZeros) {
6232     return TrailingZeros >= BitWidth
6233                ? APInt::getZero(BitWidth)
6234                : APInt::getOneBitSet(BitWidth, TrailingZeros);
6235   };
6236   auto GetGCDMultiple = [this](const SCEVNAryExpr *N) {
6237     // The result is GCD of all operands results.
6238     APInt Res = getConstantMultiple(N->getOperand(0));
6239     for (unsigned I = 1, E = N->getNumOperands(); I < E && Res != 1; ++I)
6240       Res = APIntOps::GreatestCommonDivisor(
6241           Res, getConstantMultiple(N->getOperand(I)));
6242     return Res;
6243   };
6244 
6245   switch (S->getSCEVType()) {
6246   case scConstant:
6247     return cast<SCEVConstant>(S)->getAPInt();
6248   case scPtrToInt:
6249     return getConstantMultiple(cast<SCEVPtrToIntExpr>(S)->getOperand());
6250   case scUDivExpr:
6251   case scVScale:
6252     return APInt(BitWidth, 1);
6253   case scTruncate: {
6254     // Only multiples that are a power of 2 will hold after truncation.
6255     const SCEVTruncateExpr *T = cast<SCEVTruncateExpr>(S);
6256     uint32_t TZ = getMinTrailingZeros(T->getOperand());
6257     return GetShiftedByZeros(TZ);
6258   }
6259   case scZeroExtend: {
6260     const SCEVZeroExtendExpr *Z = cast<SCEVZeroExtendExpr>(S);
6261     return getConstantMultiple(Z->getOperand()).zext(BitWidth);
6262   }
6263   case scSignExtend: {
6264     const SCEVSignExtendExpr *E = cast<SCEVSignExtendExpr>(S);
6265     return getConstantMultiple(E->getOperand()).sext(BitWidth);
6266   }
6267   case scMulExpr: {
6268     const SCEVMulExpr *M = cast<SCEVMulExpr>(S);
6269     if (M->hasNoUnsignedWrap()) {
6270       // The result is the product of all operand results.
6271       APInt Res = getConstantMultiple(M->getOperand(0));
6272       for (const SCEV *Operand : M->operands().drop_front())
6273         Res = Res * getConstantMultiple(Operand);
6274       return Res;
6275     }
6276 
6277     // If there are no wrap guarentees, find the trailing zeros, which is the
6278     // sum of trailing zeros for all its operands.
6279     uint32_t TZ = 0;
6280     for (const SCEV *Operand : M->operands())
6281       TZ += getMinTrailingZeros(Operand);
6282     return GetShiftedByZeros(TZ);
6283   }
6284   case scAddExpr:
6285   case scAddRecExpr: {
6286     const SCEVNAryExpr *N = cast<SCEVNAryExpr>(S);
6287     if (N->hasNoUnsignedWrap())
6288         return GetGCDMultiple(N);
6289     // Find the trailing bits, which is the minimum of its operands.
6290     uint32_t TZ = getMinTrailingZeros(N->getOperand(0));
6291     for (const SCEV *Operand : N->operands().drop_front())
6292       TZ = std::min(TZ, getMinTrailingZeros(Operand));
6293     return GetShiftedByZeros(TZ);
6294   }
6295   case scUMaxExpr:
6296   case scSMaxExpr:
6297   case scUMinExpr:
6298   case scSMinExpr:
6299   case scSequentialUMinExpr:
6300     return GetGCDMultiple(cast<SCEVNAryExpr>(S));
6301   case scUnknown: {
6302     // ask ValueTracking for known bits
6303     const SCEVUnknown *U = cast<SCEVUnknown>(S);
6304     unsigned Known =
6305         computeKnownBits(U->getValue(), getDataLayout(), 0, &AC, nullptr, &DT)
6306             .countMinTrailingZeros();
6307     return GetShiftedByZeros(Known);
6308   }
6309   case scCouldNotCompute:
6310     llvm_unreachable("Attempt to use a SCEVCouldNotCompute object!");
6311   }
6312   llvm_unreachable("Unknown SCEV kind!");
6313 }
