6356 getRangeForUnknownRecurrence(const SCEVUnknown *U) {
6357   const DataLayout &DL = getDataLayout();
6358 
6359   unsigned BitWidth = getTypeSizeInBits(U->getType());
6360   const ConstantRange FullSet(BitWidth, /*isFullSet=*/true);
6361 
6362   // Match a simple recurrence of the form: <start, ShiftOp, Step>, and then
6363   // use information about the trip count to improve our available range.  Note
6364   // that the trip count independent cases are already handled by known bits.
6365   // WARNING: The definition of recurrence used here is subtly different than
6366   // the one used by AddRec (and thus most of this file).  Step is allowed to
6367   // be arbitrarily loop varying here, where AddRec allows only loop invariant
6368   // and other addrecs in the same loop (for non-affine addrecs).  The code
6369   // below intentionally handles the case where step is not loop invariant.
6370   auto *P = dyn_cast<PHINode>(U->getValue());
6371   if (!P)
6372     return FullSet;
6373 
6374   // Make sure that no Phi input comes from an unreachable block. Otherwise,
6375   // even the values that are not available in these blocks may come from them,
6376   // and this leads to false-positive recurrence test.
6377   for (auto *Pred : predecessors(P->getParent()))
6378     if (!DT.isReachableFromEntry(Pred))
6379       return FullSet;
6380 
6381   BinaryOperator *BO;
6382   Value *Start, *Step;
6383   if (!matchSimpleRecurrence(P, BO, Start, Step))
6384     return FullSet;
6385 
6386   // If we found a recurrence in reachable code, we must be in a loop. Note
6387   // that BO might be in some subloop of L, and that's completely okay.
6388   auto *L = LI.getLoopFor(P->getParent());
6389   assert(L && L->getHeader() == P->getParent());
6390   if (!L->contains(BO->getParent()))
6391     // NOTE: This bailout should be an assert instead.  However, asserting
6392     // the condition here exposes a case where LoopFusion is querying SCEV
6393     // with malformed loop information during the midst of the transform.
6394     // There doesn't appear to be an obvious fix, so for the moment bailout
6395     // until the caller issue can be fixed.  PR49566 tracks the bug.
6396     return FullSet;
6397 
6398   // TODO: Extend to other opcodes such as mul, and div
6399   switch (BO->getOpcode()) {
6400   default:
6401     return FullSet;
6402   case Instruction::AShr:
6403   case Instruction::LShr:
6404   case Instruction::Shl:
6405     break;
6406   };
6407 
6408   if (BO->getOperand(0) != P)
6409     // TODO: Handle the power function forms some day.
6410     return FullSet;
6411 
6412   unsigned TC = getSmallConstantMaxTripCount(L);
6413   if (!TC || TC >= BitWidth)
6414     return FullSet;
6415 
6416   auto KnownStart = computeKnownBits(Start, DL, 0, &AC, nullptr, &DT);
6417   auto KnownStep = computeKnownBits(Step, DL, 0, &AC, nullptr, &DT);
6418   assert(KnownStart.getBitWidth() == BitWidth &&
6419          KnownStep.getBitWidth() == BitWidth);
6420 
6421   // Compute total shift amount, being careful of overflow and bitwidths.
6422   auto MaxShiftAmt = KnownStep.getMaxValue();
6423   APInt TCAP(BitWidth, TC-1);
6424   bool Overflow = false;
6425   auto TotalShift = MaxShiftAmt.umul_ov(TCAP, Overflow);
